const data = ctx.data?.objects || [];
const months = data.map(d => d.month);
const amounts = data.map(d => parseFloat(d.total_amount || 0));
const counts = data.map(d => parseInt(d.order_count || 0));
return {
  title: { text: '月度销售趋势', left: 'center', textStyle: { fontSize: 14 } },
  tooltip: { trigger: 'axis' },
  legend: { bottom: 0 },
  xAxis: { type: 'category', data: months },
  yAxis: [{ type: 'value', name: '金额' }, { type: 'value', name: '订单数' }],
  series: [
    { name: '销售额', type: 'bar', data: amounts, itemStyle: { color: '#1677ff', borderRadius: [4,4,0,0] } },
    { name: '订单数', type: 'line', yAxisIndex: 1, data: counts, smooth: true, lineStyle: { color: '#fa8c16' }, itemStyle: { color: '#fa8c16' } }
  ]
};
